import axios from 'axios';
import { API_CONFIG } from '../config/appConfig';

// Helper function to get API base URL using global configuration
const getApiUrl = (endpoint) => {
  return `${API_CONFIG.BASE_URL}${endpoint}`;
};

export const staffAPI = {
  getAll: () => axios.get(getApiUrl('/staff')),
  getById: (id) => axios.get(getApiUrl(`/staff/${id}`)),
  create: (data) => axios.post(getApiUrl('/staff'), data),
  update: (id, data) => axios.put(getApiUrl(`/staff/${id}`), data),
  delete: (id) => axios.delete(getApiUrl(`/staff/${id}`)),
  getActive: () => axios.get(getApiUrl('/staff/active'))
}
